const body = $input.first().json.body || $input.first().json;
const now = new Date();
const pad = n => String(n).padStart(3, '0');
const dateStr = now.toISOString().slice(0,10).replace(/-/g,'');

if (!body.recipe_id || !body.target_quantity) {
  throw new Error('Missing required fields: recipe_id, target_quantity');
}

const recipeMap = { 101: 'Water', 102: 'Juice', 103: 'Sauce', 201: 'Special' };
const recipeName = recipeMap[body.recipe_id] || 'Unknown';

return [{
  json: {
    order_id: `ORD-${dateStr}-${pad(Math.floor(Math.random()*999)+1)}`,
    recipe_id: body.recipe_id,
    recipe_name: recipeName,
    target_quantity: body.target_quantity,
    actual_quantity: 0,
    operator: body.operator || 'unknown',
    status: 'started',
    started_at: now.toISOString(),
    completed_at: null
  }
}];
